const VS = 220.0;
fn fl_at(c: vec2f) -> vec4f { return feedback(c); }       // REAL per-effect feedback (ping-ponged state)
fn fl_v(c: vec2f) -> vec2f { return fl_at(c).rg * VS; }   // recover real velocity

fn fieldEffect(coord: vec2f, regionMin: vec2f, regionMax: vec2f, time: f32, params: vec4f) -> vec4f {
  let dt = 1.0;
  let span = regionMax.x - regionMin.x;

  // 1 — semi-Lagrangian advection: trace back along this cell's velocity
  let advPos = coord - fl_v(coord) * dt;
  var vel = fl_v(advPos);
  var dye = fl_at(advPos).b;

  // 2 — divergence damping (cheap incompressibility): curl, don't pile up
  let vL = fl_v(coord + vec2f(-2.0, 0.0));
  let vR = fl_v(coord + vec2f( 2.0, 0.0));
  let vDn = fl_v(coord + vec2f(0.0,-2.0));
  let vUp = fl_v(coord + vec2f(0.0, 2.0));
  let div = 0.25 * ((vR.x - vL.x) + (vUp.y - vDn.y));
  vel -= vec2f(vR.x - vL.x, vUp.y - vDn.y) * clamp(div, -2.0, 2.0) * 0.03;

  // 3 — two swirling emitters, STRONG and WIDE (grid is ~512 cells, so a jet
  // needs tens of cells/frame to read as flow, not a creep)
  let t = time;
  let e1 = regionMin + (regionMax - regionMin) * vec2f(0.30, 0.42);
  let e2 = regionMin + (regionMax - regionMin) * vec2f(0.70, 0.56);
  let d1 = length(coord - e1) / span;
  let d2 = length(coord - e2) / span;
  vel += vec2f( cos(t * 1.1),  sin(t * 1.1)) * exp(-d1 * d1 * 22.0) * 22.0;
  vel += vec2f(-sin(t * 0.8),  cos(t * 0.8)) * exp(-d2 * d2 * 22.0) * 22.0;
  dye += (exp(-d1 * d1 * 34.0) + exp(-d2 * d2 * 34.0)) * 0.45;

  // 3b — YOUR CURSOR via effect.params (a hook writes cursor cell in xy, motion
  // in zw). Drag to shove the ink.
  let cur = params.xy;
  let cvel = params.zw;
  if (cur.x > 0.5) {
    let dc = length(coord - cur) / span;
    vel += cvel * exp(-dc * dc * 45.0) * 2.2;
    dye += exp(-dc * dc * 70.0) * 1.4;
  }

  // stability: kill NaN/Inf BEFORE they enter the feedback — a single poisoned
  // cell spreads through advection and blacks out the whole field within a
  // frame or two (that's the "works for a second then black").
  if (!(vel.x == vel.x) || !(vel.y == vel.y) || !(dye == dye)) { vel = vec2f(0.0); dye = 0.0; }
  vel = clamp(vel * 0.990, vec2f(-24.0), vec2f(24.0));
  dye = clamp(dye * 0.958, 0.0, 1.3);   // faster dissipation → wispy flow, not a solid fill

  // OPEN-BOUNDARY damping: fade velocity + dye to zero in a border band. Without
  // it, advection near the edge samples clamped out-of-bounds cells and smears
  // edge values inward — the streaky "edge blending" artifact. This gives clean
  // borders where the fluid simply flows out.
  let np = (coord - regionMin) / (regionMax - regionMin);
  let edge = smoothstep(0.0, 0.16, np.x) * smoothstep(0.0, 0.16, np.y)
           * smoothstep(1.0, 0.84, np.x) * smoothstep(1.0, 0.84, np.y);
  vel *= edge;
  dye *= edge;

  // SINGLE effect: output is BOTH persisted state (feedback reads rg=vel/VS,
  // b=dye) AND the image. VS is large so velocity stays near-black in R/G — the
  // display is essentially the DYE in blue, legible as ink on the blue base,
  // with velocity invisible but still driving the flow.
  let a = clamp(dye * 1.4 + length(vel) * 0.02, 0.0, 1.0);
  return vec4f(vel / VS, dye, a);
}

stepHooks.code:
try {
  const wd = sim.worldData
  if (!wd.__f3) wd.__f3 = { lx: 256, ly: 256, e: 0.5, sx: 0, sy: 0, mn: 0 }
  const S = wd.__f3
  const pdt = Math.min(dt, 0.05)

  // cursor motion stirs the cabin air — the bubble takes the energy
  const mx = wd.mouse_x, my = wd.mouse_y
  if (typeof mx === 'number') {
    const dv = Math.abs(mx - S.lx) + Math.abs(my - S.ly)
    S.e = Math.min(1.4, S.e + dv * 0.0035)
    S.lx = mx; S.ly = my
    // the bubble drifts gently toward where you point
    S.sx += (((mx / 512) - 0.5) * 1.6 - S.sx) * Math.min(1, pdt * 0.8)
    S.sy += ((0.5 - (my / 512)) * 0.9 - S.sy) * Math.min(1, pdt * 0.8)
  }

  // CLICK — poke it: a real jolt, and the water answers
  const mn = wd.mouse_down_n || 0
  if (mn !== S.mn) {
    S.mn = mn
    S.e = Math.min(1.4, S.e + 0.65)
    wd.__play_sound = [
      { frequency: 130, duration: 0.22, volume: 0.4, type: 'sine' },
      { frequency: 196, duration: 0.16, volume: 0.25, type: 'triangle' }
    ]
  }

  // zero-g: the oscillation rings long, then stills
  S.e = Math.max(0.06, S.e * (1 - pdt * 0.35))

  wd.gpuUniforms = [S.e, S.sx, S.sy]
} catch (e) { /* keep the sim alive */ }

visualTypes.wgsl:
// FLUID · 3d — a zero-g water bubble adrift in a ship's cabin.
// Hybrid renderer: the cabin is an ANALYTIC box interior (no marching — every
// ray finds its wall exactly), the bubble is a raymarched wobbling sphere with
// real Fresnel, refraction through the body (Beer-law absorption), and
// speculars from the ceiling light strips. uni(0)=wobble energy, uni(1,2)=sway.

fn f3_room(ro: vec3f, rd: vec3f, bub: vec3f, br: f32, t: f32) -> vec3f {
  // interior box: x ±6, y ±3, z -4..10 — nearest positive exit per axis
  let inv = vec3f(
    select(1.0 / rd.x, 1e9, abs(rd.x) < 1e-5),
    select(1.0 / rd.y, 1e9, abs(rd.y) < 1e-5),
    select(1.0 / rd.z, 1e9, abs(rd.z) < 1e-5));
  let tx = (select(-6.0, 6.0, rd.x > 0.0) - ro.x) * inv.x;
  let ty = (select(-3.0, 3.0, rd.y > 0.0) - ro.y) * inv.y;
  let tz = (select(-4.0, 10.0, rd.z > 0.0) - ro.z) * inv.z;
  let th = min(tx, min(ty, tz));
  let h = ro + rd * th;

  var col = vec3f(0.0);
  // shared panel language: seams + brushed metal grain
  let grain = vnoise(h.xz * 7.0 + h.y * 3.0) * 0.05;
  let base = vec3f(0.135, 0.14, 0.15) + grain;

  if (th == ty && rd.y > 0.0) {
    // CEILING — two long light strips run the cabin, warm white
    var c = base * 0.8;
    let seam = min(fract(h.x * 0.5), fract(h.z * 0.33));
    c *= 0.75 + 0.25 * smoothstep(0.0, 0.06, seam);
    for (var k = 0; k < 2; k++) {
      let sx = select(-1.8, 1.8, k == 1);
      let strip = smoothstep(0.62, 0.42, abs(h.x - sx)) * smoothstep(8.5, 8.0, h.z) * smoothstep(-2.5, -2.0, h.z);
      c = mix(c, vec3f(3.4, 3.15, 2.7), strip);
    }
    col = c;
  } else if (th == ty) {
    // FLOOR — dark grating, light-strip sheen, the bubble's soft shadow
    var c = base * 0.55;
    let gx = abs(fract(h.x * 1.4) - 0.5);
    let gz = abs(fract(h.z * 1.4) - 0.5);
    c *= 0.55 + 0.45 * smoothstep(0.0, 0.08, min(gx, gz));
    c += vec3f(0.5, 0.47, 0.4) * (exp(-abs(h.x - 1.8) * 1.2) + exp(-abs(h.x + 1.8) * 1.2)) * 0.16;
    let dd = length(h.xz - bub.xz);
    c *= 1.0 - 0.55 * smoothstep(br * 2.6, br * 0.7, dd);
    col = c;
  } else if (th == tz && rd.z > 0.0) {
    // AFT WALL — the porthole: stars and a dark nebula, metal ring, panels
    let r = length(h.xy - vec2f(0.0, 0.35));
    if (r < 2.35) {
      let sp = (h.xy - vec2f(0.0, 0.35)) * 9.0;
      let cell = floor(sp);
      let hs = hash21(cell);
      var c = vec3f(0.004, 0.004, 0.007);
      c += vec3f(0.02, 0.015, 0.03) * fbm3(h.xy * 0.8 + vec2f(2.7, 5.1));            // faint nebula, violet-grey
      let tw = 0.6 + 0.4 * sin(t * (0.6 + hs * 1.2) + hs * 40.0);
      c += vec3f(0.85, 0.88, 0.95) * step(0.986, hs) * smoothstep(0.32, 0.05, length(fract(sp) - 0.5)) * tw;
      col = c;
    } else if (r < 2.7) {
      col = vec3f(0.30, 0.30, 0.32) * (0.7 + 0.3 * sin(atan2(h.y - 0.35, h.x) * 24.0));  // bolted rim
    } else {
      var c = base;
      let seam = min(fract(h.x * 0.5), fract(h.y * 0.7));
      c *= 0.72 + 0.28 * smoothstep(0.0, 0.05, seam);
      col = c;
    }
  } else if (th == tz) {
    // FORE WALL (behind camera — lives in reflections): doorway outline glow
    var c = base * 0.9;
    let door = max(abs(h.x) - 1.1, abs(h.y + 0.4) - 1.7);
    c += vec3f(0.25, 0.5, 0.45) * smoothstep(0.10, 0.0, abs(door)) * 0.8;
    col = c;
  } else {
    // SIDE WALLS — panels, pipe bands, and a console of blinking LEDs starboard
    var c = base;
    let seam = min(fract(h.z * 0.5), fract(h.y * 0.7));
    c *= 0.72 + 0.28 * smoothstep(0.0, 0.05, seam);
    c *= 0.85 + 0.15 * sin(h.y * 2.2);                       // pipe banding
    if (rd.x > 0.0 && h.z > 0.5 && h.z < 4.5 && abs(h.y - 0.2) < 1.0) {
      let lp = vec2f(floor(h.z * 4.0), floor((h.y - 0.2) * 4.0));
      let hl = hash21(lp);
      let blink = step(0.5, fract(t * (0.2 + hl * 0.5) + hl));
      let led = smoothstep(0.42, 0.2, length(fract(vec2f(h.z * 4.0, (h.y - 0.2) * 4.0)) - 0.5));
      let ledc = mix(vec3f(1.2, 0.35, 0.1), mix(vec3f(0.1, 1.1, 0.5), vec3f(0.2, 0.6, 1.2), step(0.66, hl)), step(0.33, hl));
      c = mix(c * 0.6, ledc, led * blink * 0.9);
    }
    col = c;
  }
  // depth falloff — the cabin dims into its corners
  return col / (1.0 + th * 0.045);
}

fn f3_sdf(p: vec3f, bub: vec3f, br: f32, t: f32, amp: f32) -> f32 {
  let q = p - bub;
  let r = length(q);
  let d = q / max(r, 1e-4);
  // zero-g oscillation: low-order surface modes, driven by the poke energy
  var w = sin(d.x * 4.0 + t * 2.3) * sin(d.y * 3.0 - t * 1.9) * 0.5;
  w += sin(d.z * 5.0 + t * 1.5) * sin((d.x + d.y) * 3.5 - t * 2.7) * 0.35;
  w += sin((d.y + d.z) * 6.0 + t * 3.4) * 0.2;
  return r - br * (1.0 + w * amp);
}

fn f3_nrm(p: vec3f, bub: vec3f, br: f32, t: f32, amp: f32) -> vec3f {
  let e = 0.004;
  let d0 = f3_sdf(p, bub, br, t, amp);
  return normalize(vec3f(
    f3_sdf(p + vec3f(e, 0.0, 0.0), bub, br, t, amp) - d0,
    f3_sdf(p + vec3f(0.0, e, 0.0), bub, br, t, amp) - d0,
    f3_sdf(p + vec3f(0.0, 0.0, e), bub, br, t, amp) - d0));
}

fn f3_spec(n: vec3f, v: vec3f, p: vec3f) -> vec3f {
  // the two ceiling strips as light rows — three point samples each
  var s = vec3f(0.0);
  for (var k = 0; k < 6; k++) {
    let sx = select(-1.8, 1.8, k >= 3);
    let sz = f32(k % 3) * 3.4 - 1.4;
    let L = normalize(vec3f(sx, 2.9, sz) - p);
    let hv = normalize(L + v);
    s += vec3f(1.0, 0.95, 0.85) * pow(max(dot(n, hv), 0.0), 240.0) * 1.4;
  }
  return s;
}

fn visual_fluid_base(uv: vec2f, sdf: f32, color: vec4f, time: f32, params: vec4f, behind: vec4f) -> vec4f {
  let t = time;
  let energy = clamp(uni(0), 0.0, 1.4);
  let amp = 0.022 + energy * 0.075;

  // camera: seated in the cabin, looking aft at the bubble
  let bub = vec3f(uni(1) * 1.4, 0.35 + sin(t * 0.47) * 0.28 + uni(2), 1.6 + sin(t * 0.31) * 0.3);
  let br = 1.05;
  let ro = vec3f(0.0, 0.15, -3.4);
  let ta = vec3f(bub.x * 0.35, 0.3, 1.6);
  let fw = normalize(ta - ro);
  let rt = normalize(cross(fw, vec3f(0.0, 1.0, 0.0)));
  let up = cross(rt, fw);
  let rd = normalize(fw * 1.5 + rt * uv.x - up * uv.y);

  // bounding sphere gate — most rays never march
  let oc = ro - bub;
  let bq = dot(oc, rd);
  let bc = dot(oc, oc) - (br * 1.30) * (br * 1.30);
  let disc = bq * bq - bc;

  var col = f3_room(ro, rd, bub, br, t);

  if (disc > 0.0) {
    let t0 = max(-bq - sqrt(disc), 0.0);
    let t1 = -bq + sqrt(disc);
    var tm = t0;
    var hitS = false;
    for (var i = 0; i < 44; i++) {
      let d = f3_sdf(ro + rd * tm, bub, br, t, amp);
      if (d < 0.0025) { hitS = true; break; }
      tm += d * 0.9;
      if (tm > t1) { break; }
    }
    if (hitS) {
      let hp = ro + rd * tm;
      let n = f3_nrm(hp, bub, br, t, amp);
      // Fresnel (Schlick, F0 of water)
      let cosi = max(dot(n, -rd), 0.0);
      let F = 0.02 + 0.98 * pow(1.0 - cosi, 5.0);
      // reflection of the cabin
      let refl = f3_room(hp, reflect(rd, n), bub, br, t);
      // refraction through the body: enter, cross the chord, exit, see the cabin
      var trans = vec3f(0.0);
      let rr = refract(rd, n, 0.752);
      if (length(rr) > 0.001) {
        let chord = max(2.0 * dot(bub - hp, rr), br * 0.2);
        let xp = hp + rr * chord;
        let xn = normalize(bub - xp);            // inward normal at exit → outward is -xn
        var ro2 = refract(rr, xn, 1.33);
        if (length(ro2) < 0.001) { ro2 = reflect(rr, xn); }  // TIR folds the cabin back in
        let seen = f3_room(xp, normalize(ro2), bub, br, t);
        // water drinks red first — the body reads faintly aqua, never blue
        trans = seen * exp(-vec3f(0.30, 0.10, 0.08) * chord * 0.55);
        // internal glints — micro-bubbles catching the strips
        let gl = vnoise(hp.xy * 9.0 + vec2f(t * 0.6, hp.z * 5.0));
        trans += vec3f(0.9, 0.9, 0.85) * smoothstep(0.93, 1.0, gl) * 0.25;
      }
      col = mix(trans, refl, F) + f3_spec(n, -rd, hp);
      // whisper of a rim — surface tension catching the light
      col += vec3f(0.35, 0.36, 0.34) * pow(1.0 - cosi, 3.0) * 0.22;
    }
  }

  // filmic-ish grade, no blue cast
  col = col / (col + vec3f(0.85));
  col = pow(col, vec3f(0.92));
  return vec4f(col, 1.0);
}
